$studentId..write:
auth != null && (
              (
                root.child('users/' + auth.uid + '/universityId').val() === $universityId && (
                  root.child('users/' + auth.uid + '/role').val() === 'teacher'
                )
              ) ||
              root.child('users/' + auth.uid + '/role').val() === 'super_admin_plateforme'
            )

$studentId..read:
auth != null && (
              (
                root.child('users/' + auth.uid + '/universityId').val() === $universityId && (
                  auth.uid === $studentId ||
                  root.child('users/' + auth.uid + '/role').val() === 'admin_universite' ||
                  root.child('users/' + auth.uid + '/linkedStudentIds/' + $studentId).val() === true
                )
              ) ||
              root.child('users/' + auth.uid + '/role').val() === 'super_admin_plateforme'
            )

$studentId..write:
auth != null && (
              (
                root.child('users/' + auth.uid + '/universityId').val() === $universityId && (
                  root.child('users/' + auth.uid + '/role').val() === 'admin_universite'
                )
              ) ||
              root.child('users/' + auth.uid + '/role').val() === 'super_admin_plateforme'
            )
